55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const MAIN_ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	};
68	
69	const COMPONENT_BASE_PREMIUMS: Record<string, number> = {
70	  rune: 25,
71	  moonstone: 25,
72	};
73	
74	const ITEM_BASE_PREMIUMS: Record<string, number> = {
75	  ...MAIN_ITEM_BASE_PREMIUMS,
76	  ...COMPONENT_BASE_PREMIUMS,
77	};
78	
79	const COMPONENT_TYPES = new Set(Object.keys(COMPONENT_BASE_PREMIUMS));
80	const BLOCK_SIZE = 3;
81	const BLOCK_BASE = 60;
82	
83	const CURSE_SURCHARGE_RATE = 0.5;
84	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
85	const HIGH_ENCHANTMENT_THRESHOLD = 5;
86	const LOYALTY_DISCOUNT_RATE = 0.2;
87	const LOYALTY_THRESHOLD_YEARS = 2;
88	
89	const itemBase = (type: string): number => ITEM_BASE_PREMIUMS[type] ?? 0;
90	
91	const componentGroupBase = (count: number, unitBase: number): number => {
92	  if (count === BLOCK_SIZE) return BLOCK_BASE;
93	  return count * unitBase;
94	};
95	
96	const itemSurchargeRate = (item: Item): number => {
97	  let rate = 0;
98	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
99	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
100	    rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
101	  }
102	  return rate;
103	};
104	
105	const itemSurcharge = (item: Item, base: number): number =>
106	  base * itemSurchargeRate(item);
107	
108	const policyModifierRate = (customer: Customer): number => {
109	  let rate = FIRST_INSURANCE_SURCHARGE_RATE;
110	  if (customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
111	    rate -= LOYALTY_DISCOUNT_RATE;
112	  }
113	  return rate;
114	};
115	
116	const quotePremium = (items: Item[], customer: Customer): number => {
117	  let policyBase = 0;
118	  let itemSurchargeTotal = 0;
119	  const componentCounts = new Map<string, number>();
120	
121	  for (const item of items) {
122	    if (COMPONENT_TYPES.has(item.type)) {
123	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
124	    } else {
125	      const base = itemBase(item.type);
126	      policyBase += base;
127	      itemSurchargeTotal += itemSurcharge(item, base);
128	    }
129	  }
130	
131	  for (const [type, count] of componentCounts) {
132	    const groupBase = componentGroupBase(count, itemBase(type));
133	    policyBase += groupBase;
134	  }
135	
136	  const policyModifier = policyBase * policyModifierRate(customer);
137	  const total = policyBase + itemSurchargeTotal + policyModifier;
138	  return roundUp(total) + PROCESSING_FEE;
139	};
140	
141	export const processScenario = (scenario: Scenario): ScenarioResult => {
142	  const results: StepResult[] = scenario.steps.map((step) => {
143	    if (step.op === "quote") {
144	      return { premium: quotePremium(step.items, scenario.customer) };
145	    }
146	    return { payout: 0, remainingCap: 0 };
147	  });
148	  return { results };
149	};
